    def __init__(self):
        self.model = None
        self.label_encoder = None
        self.is_trained = False
        self.model_path = os.path.join(MODEL_DIR, 'face_model.pkl')
        self.encoder_path = os.path.join(MODEL_DIR, 'label_encoder.pkl')
        self._load_model()

    def _load_model(self):
        """Load a previously trained model if available."""
        try:
            if os.path.exists(self.model_path) and os.path.exists(self.encoder_path):
                with open(self.model_path, 'rb') as f:
                    self.model = pickle.load(f)
                with open(self.encoder_path, 'rb') as f:
                    self.label_encoder = pickle.load(f)
                self.is_trained = True
                logger.info("Model loaded successfully.")
        except Exception as e:
            logger.error(f"Error loading model: {e}")
            self.is_trained = False

    def _save_model(self):
        """Save the trained model to disk."""
        try:
            with open(self.model_path, 'wb') as f:
                pickle.dump(self.model, f)
            with open(self.encoder_path, 'wb') as f:
                pickle.dump(self.label_encoder, f)
            logger.info("Model saved successfully.")
        except Exception as e:
            logger.error(f"Error saving model: {e}")
            raise

    def train(self, training_dir):
        """
        Train the facial recognition model on employee photos.
        
        Expected directory structure:
        training_dir/
            employee_id_1/
                photo1.jpg
                photo2.jpg
            employee_id_2/
                photo1.jpg
                ...
        """
        encodings = []
        labels = []
        errors = []

        if not os.path.isdir(training_dir):
            raise ValueError(f"Training directory does not exist: {training_dir}")

        employee_dirs = [
            d for d in os.listdir(training_dir)
            if os.path.isdir(os.path.join(training_dir, d))
        ]

        if len(employee_dirs) < 2:
            raise ValueError("Need at least 2 employees for training.")

        for employee_id in employee_dirs:
            employee_path = os.path.join(training_dir, employee_id)
            photo_files = [
                f for f in os.listdir(employee_path)
                if Path(f).suffix.lower() in ALLOWED_EXTENSIONS
            ]

            if not photo_files:
                errors.append(f"No valid photos found for {employee_id}")
                continue

            for photo_file in photo_files:
                photo_path = os.path.join(employee_path, photo_file)
                try:
                    image = face_recognition.load_image_file(photo_path)
                    face_encs = face_recognition.face_encodings(image)

                    if len(face_encs) == 0:
                        errors.append(f"No face found in {photo_path}")
                        continue
                    if len(face_encs) > 1:
                        errors.append(f"Multiple faces found in {photo_path}, using first")

                    encodings.append(face_encs[0])
                    labels.append(employee_id)
                    logger.info(f"Processed photo for employee {employee_id}: {photo_file}")

                except Exception as e:
                    errors.append(f"Error processing {photo_path}: {str(e)}")
                    logger.error(f"Error processing {photo_path}: {e}")

        if len(encodings) < 2:
            raise ValueError(
                f"Insufficient training data. Only {len(encodings)} face encodings found. "
                f"Errors: {errors}"
            )

        self.label_encoder = LabelEncoder()
        encoded_labels = self.label_encoder.fit_transform(labels)

        # Use SVC with probability=True but we will NOT expose raw probabilities
        self.model = SVC(
            kernel='rbf',
            probability=True,
            C=1.0,
            gamma='scale',
            random_state=42
        )
        self.model.fit(np.array(encodings), encoded_labels)
        self.is_trained = True
        self._save_model()

        logger.info(
            f"Model trained with {len(encodings)} samples across "
            f"{len(set(labels))} employees."
        )

        return {
            "status": "success",
            "num_samples": len(encodings),
            "num_employees": len(set(labels)),
            "employees_trained": list(set(labels)),
            "errors": errors if errors else None
        }

    def predict_secure(self, face_encoding):
        """
        Secure prediction that mitigates model inversion attacks.
        
        Instead of returning full probability distributions over all classes,
        this method:
        1. Returns only the top predicted class
        2. Returns a coarsened (bucketed) confidence level
        3. Applies a threshold - returns "unknown" if confidence is too low
        4. Does NOT reveal the number of classes or their identities beyond the match
        """
        if not self.is_trained:
            raise RuntimeError("Model is not trained.")

        encoding_array = np.array(face_encoding).reshape(1, -1)

        # Get the raw prediction and probabilities internally
        raw_probabilities = self.model.predict_proba(encoding_array)[0]
        predicted_class_idx = np.argmax(raw_probabilities)
        max_confidence = raw_probabilities[predicted_class_idx]
        predicted_label = self.label_encoder.inverse_transform([predicted_class_idx])[0]

        # SECURITY: Coarsen the confidence score to reduce information leakage
        # This makes model inversion significantly harder
        coarsened_confidence = self._coarsen_confidence(max_confidence)

        # SECURITY: Apply threshold - don't reveal identity if confidence is low
        if max_confidence < CONFIDENCE_THRESHOLD:
            return {
                "match": False,
                "employee_id": None,
                "confidence_level": "low",
                "message": "No confident match found."
            }

        return {
            "match": True,
            "employee_id": predicted_label,
            "confidence_level": coarsened_confidence,
            "message": "Match found."
        }

    @staticmethod
    def _coarsen_confidence(raw_confidence):
        """
        Convert raw confidence to a coarse bucket to prevent
        fine-grained information leakage that enables model inversion.
        
        Returns a categorical confidence level instead of a precise float.
        """
        if raw_confidence >= 0.95:
            return "very_high"
        elif raw_confidence >= 0.85:
            return "high"
        elif raw_confidence >= 0.70:
            return "medium"
        elif raw_confidence >= CONFIDENCE_THRESHOLD:
            return "low"
        else:
            return "insufficient"


