def load_api_keys():
    """Load API keys from environment or secure storage."""
    keys_str = os.environ.get('API_KEYS', '')
    if keys_str:
        for entry in keys_str.split(','):
            parts = entry.strip().split(':')
            if len(parts) == 2:
                key_hash = hashlib.sha256(parts[1].encode()).hexdigest()
                API_KEYS[key_hash] = {
                    'user': parts[0],
                    'key_hash': key_hash
                }

