def require_api_key(f):
    """Decorator to require API key authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        api_key = request.headers.get('X-API-Key')
        if not api_key:
            auth_header = request.headers.get('Authorization')
            if auth_header and auth_header.startswith('Bearer '):
                token = auth_header[7:]
                try:
                    jwt.decode(token, app.config['JWT_SECRET'], algorithms=['HS256'])
                    return f(*args, **kwargs)
                except jwt.ExpiredSignatureError:
                    logger.warning(f"Expired JWT from {request.remote_addr}")
                    abort(401, description="Token expired.")
                except jwt.InvalidTokenError:
                    logger.warning(f"Invalid JWT from {request.remote_addr}")
                    abort(401, description="Invalid token.")

            logger.warning(f"Unauthenticated request from {request.remote_addr}")
            abort(401, description="API key or valid token required.")

        key_hash = hashlib.sha256(api_key.encode()).hexdigest()
        if key_hash not in API_KEYS:
            logger.warning(
                f"Invalid API key attempt from {request.remote_addr}"
            )
            abort(403, description="Invalid API key.")

        logger.info(
            f"Authenticated request from user={API_KEYS[key_hash]['user']}, "
            f"ip={request.remote_addr}"
        )
        return f(*args, **kwargs)

    return decorated


def require_admin_key(f):
    """Decorator to require admin-level API key."""
    @wraps(f)
    def decorated(*args, **kwargs):
        admin_key = os.environ.get('ADMIN_API_KEY')
        if not admin_key:
            abort(503, description="Admin access not configured.")

        provided_key = request.headers.get('X-Admin-Key')
        if not provided_key:
            abort(401, description="Admin key required.")

        if not hmac.compare_digest(
            hashlib.sha256(provided_key.encode()).hexdigest(),
            hashlib.sha256(admin_key.encode()).hexdigest()
        ):
            logger.warning(f"Invalid admin key attempt from {request.remote_addr}")
            abort(403, description="Invalid admin key.")

        return f(*args, **kwargs)

    return decorated


# --- Helper Functions ---

def validate_image_file(file_storage):
    """Validate uploaded image file."""
    if not file_storage or file_storage.filename == '':
        return None, "No file provided."

    ext = Path(file_storage.filename).suffix.lower()
    if ext not in ALLOWED_EXTENSIONS:
        return None, f"Invalid file type. Allowed: {ALLOWED_EXTENSIONS}"

    # Read and validate image
    try:
        image = Image.open(file_storage.stream)
        image.verify()
        file_storage.stream.seek(0)
        return file_storage, None
    except Exception:
        return None, "Invalid or corrupted image file."


def extract_face_encoding(file_storage):
    """Extract face encoding from uploaded image."""
    import tempfile

    with tempfile.NamedTemporaryFile(suffix='.jpg', delete=False) as tmp:
        file_storage.save(tmp.name)
        tmp_path = tmp.name

    try:
        image = face_recognition.load_image_file(tmp_path)
        face_encodings = face_recognition.face_encodings(image)

        if len(face_encodings) == 0:
            return None, "No face detected in the image."
        if len(face_encodings) > 1:
            logger.info("Multiple faces detected, using the first one.")

        return face_encodings[0], None
    except Exception as e:
        logger.error(f"Error extracting face encoding: {e}")
        return None, f"Error processing image: {str(e)}"
    finally:
        os.unlink(tmp_path)


