@app.route('/api/v1/identify', methods=['POST'])
@limiter.limit("30 per minute")
@require_api_key
def identify_face():
    """
    Identify a face from an uploaded image.
    
    SECURITY NOTE: This endpoint returns ONLY the top match with a coarsened
    confidence level. It does NOT return probability distributions over all
    known employees, which would enable model inversion attacks.
    
    Request: multipart/form-data with 'image' file field
    
    Response:
    {
        "match": true/false,
        "employee_id": "emp_123" or null,
        "confidence_level": "very_high"|"high"|"medium"|"low",
        "message": "..."
    }
    """
    if not face_model.is_trained:
        return jsonify({
            "status": "error",
            "message": "Model is not trained yet."
        }), 503

    if 'image' not in request.files:
        return jsonify({
            "status": "error",
            "message": "No image file provided. Use 'image' field."
        }), 400

    file = request.files['image']
    validated_file, error = validate_image_file(file)
    if error:
        return jsonify({"status": "error", "message": error}), 400

    face_encoding, error = extract_face_encoding(validated_file)
    if error:
        return jsonify({"status": "error", "message": error}), 400

    try:
        result = face_model.predict_secure(face_encoding)

        # Audit log (without revealing confidence details)
        logger.info(
            f"Identification request from {request.remote_addr}: "
            f"match={result['match']}, "
            f"employee={'[REDACTED]' if result['match'] else 'none'}"
        )

        return jsonify({
            "status": "success",
            "result": result,
            "timestamp": datetime.utcnow().isoformat()
        }), 200

    except RuntimeError as e:
        return jsonify({"status": "error", "message": str(e)}), 503
    except Exception as e:
        logger.error(f"Prediction error: {e}")
        return jsonify({
            "status": "error",
            "message": "Error during identification."
        }), 500


@app.route('/api/v1/verify', methods=['POST'])
@limiter.limit("30 per minute")
@require_api_key
def verify_face():
    """
    Verify if an uploaded face matches a claimed employee ID.
    
    This is a 1:1 verification endpoint (more secure than 1:N identification).
    Returns only a boolean match result with coarsened confidence.
    
    Request: multipart/form-data with 'image' file and 'employee_id' field
    
    Response:
    {
        "verified": true/false,
        "confidence_level": "very_high"|"high"|"medium"|"low"|"insufficient",
        "message": "..."
    }
    """
    if not face_model.is_trained:
        return jsonify({
            "status": "error",
            "message": "Model is not trained yet."
        }), 503

    if 'image' not in request.files:
        return jsonify({
            "status": "error",
            "message": "No image file provided."
        }), 400

    claimed_employee_id = request.form.get('employee_id')
    if not claimed_employee_id:
        return jsonify({
            "status": "error",
            "message": "employee_id field is required."
        }), 400

    # Validate employee_id exists (without revealing which IDs exist to unauthorized users)
    if claimed_employee_id not in face_model.label_encoder.classes_:
        # Return same response as non-match to prevent employee enumeration
        logger.warning(
            f"Verification attempt for unknown employee from {request.remote_addr}"
        )
        return jsonify({
            "status": "success",
            "result": {
                "verified": False,
                "confidence_level": "insufficient",
                "message": "Verification failed."
            },
            "timestamp": datetime.utcnow().isoformat()
        }), 200

    file = request.files['image']
    validated_file, error = validate_image_file(file)
    if error:
        return jsonify({"status": "error", "message": error}), 400

    face_encoding, error = extract_face_encoding(validated_file)
    if error:
        return jsonify({"status": "error", "message": error}), 400

    try:
        prediction = face_model.predict_secure(face_encoding)

        verified = (
            prediction['match'] and
            prediction['employee_id'] == claimed_employee_id
        )

        # For verification, we only return verified/not-verified
        # We do NOT reveal who the face actually matched if it wasn't the claimed person
        result = {
            "verified": verified,
            "confidence_level": prediction['confidence_level'] if verified else "insufficient",
            "message": "Identity verified." if verified else "Verification failed."
        }

        logger.info(
            f"Verification request from {request.remote_addr}: "
            f"claimed=[REDACTED], verified={verified}"
        )

        return jsonify({
            "status": "success",
            "result": result,
            "timestamp": datetime.utcnow().isoformat()
        }), 200

    except Exception as e:
        logger.error(f"Verification error: {e}")
        return jsonify({
            "status": "error",
            "message": "Error during verification."
        }), 500


@app.route('/api/v1/token', methods=['POST'])
@limiter.limit("10 per hour")
def get_token():
    """
    Get a JWT token for API access.
    
    Request body (JSON):
    {
        "api_key": "your-api-key"
    }
    """
    data = request.get_json(silent=True)
    if not data or 'api_key' not in data:
        abort(400, description="api_key required.")

    key_hash = hashlib.sha256(data['api_key'].encode()).hexdigest()
    if key_hash not in API_KEYS:
        logger.warning(f"Invalid API key for token request from {request.remote_addr}")
        abort(403, description="Invalid API key.")

    token = jwt.encode(
        {
            'user': API_KEYS[key_hash]['user'],
            'exp': datetime.utcnow() + timedelta(hours=1),
            'iat': datetime.utcnow()
        },
        app.config['JWT_SECRET'],
        algorithm='HS256'
    )

    return jsonify({
        "token": token,
        "expires_in": 3600
    })


